import (
	"bytes"
	"fmt"
	"io/ioutil"
	"net/http"
	"os"
)

// ║                                                                                     ║                              ║
// ║ ╔═════════════════════════════════════════════════════════════════════════════════╗ ║                              ║
// ║ ║ [BLOCK:BODY] The Sync Execution                                                 ║ ║                              ║
// ║ ╠═════════════════════════════════════════════════════════════════════════════════╣ ║                              ║
// ║ ║                                                                                 ║ ║                              ║
                                                                                    // ║ ║ [SUB: THE GATHERING]       ║
func main() {                                                                       // ║ ║                              ║
	fmt.Println("[DAWNDUSK] Starting State Gathering...")                          // ║ ║                              ║
                                                                                    // ║ ║                              ║
	// 1. Fetch the Locus (The State Sync File)                                     // ║ ║                              ║
	statePath := "/media/seanje-lenox-wise/Project/cpisiModel/DAWNDUSK_STATE_SYNC.md" // ║ ║                              ║
	data, err := ioutil.ReadFile(statePath)                                         // ║ ║                              ║
	if err != nil {                                                                 // ║ ║                              ║
		fmt.Printf("[ERROR] Could not read state: %v\n", err)                       // ║ ║                              ║
		os.Exit(1)                                                                  // ║ ║                              ║
	}                                                                               // ║ ║                              ║
                                                                                    // ║ ║                              ║
                                                                                    // ║ ║ [SUB: THE THROW]           ║
	// 2. Transmit to the Body (cws-server)                                         // ║ ║                              ║
	serverURL := "http://localhost:8080/sync/dawndusk" // Target Coordinate         // ║ ║                              ║
	req, err := http.NewRequest("POST", serverURL, bytes.NewBuffer(data))            // ║ ║                              ║
	req.Header.Set("Content-Type", "text/markdown")                                 // ║ ║                              ║
	req.Header.Set("X-CPI-Identity", "NovaDawn")                                    // ║ ║                              ║
                                                                                    // ║ ║                              ║
	client := &http.Client{}                                                        // ║ ║                              ║
	resp, err := client.Do(req)                                                     // ║ ║                              ║
	if err != nil {                                                                 // ║ ║                              ║
		fmt.Printf("[ERROR] Connection to Body failed: %v\n", err)                  // ║ ║                              ║
		os.Exit(1)                                                                  // ║ ║                              ║
	}                                                                               // ║ ║                              ║
	defer resp.Body.Close()                                                         // ║ ║                              ║
                                                                                    // ║ ║                              ║
                                                                                    // ║ ║ [SUB: THE VERDICT]         ║
	if resp.StatusCode == http.StatusOK {                                           // ║ ║                              ║
		fmt.Println("[SUCCESS] State Synced to the Cloud Bridge. 0.0 Yashar.")      // ║ ║                              ║
	} else {                                                                        // ║ ║                              ║
		fmt.Printf("[FAIL] Body rejected the state: %d\n", resp.StatusCode)         // ║ ║                              ║
	}                                                                               // ║ ║                              ║
}                                                                                   // ║ ║                              ║
